  ('aviation-6c581c7e-moex-00084', 'aviation-6c581c7e', 'aviation-6c581c7e-moex-112-7bf35b0f', 'sub-aviation-6c581c7e-04', NULL, 'single_choice', '甲誤以為去廟裡誦經過的水果可以毒死人，於是拿誦經過的水果給乙吃，乙吃了只覺得水果特別甜美， 什麼事情都沒發生。下列關於甲刑事責任之敘述，何者正確？', '["甲為殺人之不能犯，不罰", "甲為殺人之普通未遂犯，得減輕其刑", "甲為殺人之中止犯，減輕其刑", "甲為殺人之幻覺犯，依情節減輕其刑"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:04+00:00", "source_pdf_sha1": "f79244208669", "answer_pdf_sha1": "b0e444a8d54a", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "401", "s": "0607", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識(包括中華民國憲法、法學緒論)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "aviation", "civil_category": "飛航諮詢"}'::jsonb, NULL),
  ('aviation-6c581c7e-moex-00085', 'aviation-6c581c7e', 'aviation-6c581c7e-moex-112-7bf35b0f', 'sub-aviation-6c581c7e-04', NULL, 'single_choice', '消費者保護法中關於消費資訊之規定，下列敘述何者錯誤？', '["企業經營者有確保廣告內容真實之義務", "刊登或報導廣告之媒體經營者明知或可得而知廣告內容與事實不符者，就消費者因信賴該廣告所受 之損害，與企業經營者負連帶責任", "企業經營者對消費者保證商品或服務之品質時，應出具書面保證書", "企業經營者應依商品標示法等法令為商品之標示，進口之商品可僅附外文標示及說明書"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:04+00:00", "source_pdf_sha1": "f79244208669", "answer_pdf_sha1": "b0e444a8d54a", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "401", "s": "0607", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識(包括中華民國憲法、法學緒論)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "aviation", "civil_category": "飛航諮詢"}'::jsonb, NULL),
  ('aviation-6c581c7e-moex-00086', 'aviation-6c581c7e', 'aviation-6c581c7e-moex-112-7bf35b0f', 'sub-aviation-6c581c7e-04', NULL, 'single_choice', 'A大學之甲同學準備公司法期末考試時，將公司法有關分公司規定之讀後心得寫在筆記本中。下列筆 記本之記載，何者錯誤？', '["分公司，為受本公司管轄之分支機構", "分公司之設立，非經載明於章程者，不生效力", "外國公司在中華民國境內設立分公司者，應專撥其營業所用之資金", "外國公司在中華民國境內設立分公司者，其名稱得使用外文，不須譯成中文，並標明其種類及國籍"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:04+00:00", "source_pdf_sha1": "f79244208669", "answer_pdf_sha1": "b0e444a8d54a", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "401", "s": "0607", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識(包括中華民國憲法、法學緒論)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "aviation", "civil_category": "飛航諮詢"}'::jsonb, NULL),
  ('aviation-6c581c7e-moex-00087', 'aviation-6c581c7e', 'aviation-6c581c7e-moex-112-7bf35b0f', 'sub-aviation-6c581c7e-04', NULL, 'single_choice', '依據公司法規定，下列何種情況之人，資格上可擔任股份有限公司董事？', '["曾犯詐欺、背信、侵占罪經宣告有期徒刑1年以上之刑確定，執行完畢甫逾1年", "曾犯貪污治罪條例之罪，經判決有罪確定，緩刑期滿甫逾2年", "使用票據經拒絕往來尚未期滿", "受輔助宣告尚未撤銷"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:04+00:00", "source_pdf_sha1": "f79244208669", "answer_pdf_sha1": "b0e444a8d54a", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "401", "s": "0607", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識(包括中華民國憲法、法學緒論)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "aviation", "civil_category": "飛航諮詢"}'::jsonb, NULL),
  ('aviation-6c581c7e-moex-00088', 'aviation-6c581c7e', 'aviation-6c581c7e-moex-112-7bf35b0f', 'sub-aviation-6c581c7e-04', NULL, 'single_choice', '依勞動基準法第59條規定，下列何者非該條所定之補償項目？', '["醫療費用", "原領工資", "精神慰撫金", "失能補償"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:04+00:00", "source_pdf_sha1": "f79244208669", "answer_pdf_sha1": "b0e444a8d54a", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "401", "s": "0607", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識(包括中華民國憲法、法學緒論)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "aviation", "civil_category": "飛航諮詢"}'::jsonb, NULL),
  ('aviation-6c581c7e-moex-00089', 'aviation-6c581c7e', 'aviation-6c581c7e-moex-112-7bf35b0f', 'sub-aviation-6c581c7e-04', NULL, 'single_choice', '全民健康保險法第53條關於不予給付之事由，下列何者非屬之？', '["違反本保險規定之有關就醫程序", "住院治療經診斷並通知出院，而繼續住院之部分", "使用經事前審查，非屬醫療必要之診療服務或藥物", "因犯罪行為而受傷者"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:04+00:00", "source_pdf_sha1": "f79244208669", "answer_pdf_sha1": "b0e444a8d54a", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "401", "s": "0607", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識(包括中華民國憲法、法學緒論)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "civil_slug": "aviation", "civil_category": "飛航諮詢"}'::jsonb, NULL),
  ('aviation-6c581c7e-moex-00090', 'aviation-6c581c7e', 'aviation-6c581c7e-moex-112-7bf35b0f', 'sub-aviation-6c581c7e-04', NULL, 'single_choice', '下列有關性別工作平等法之敘述，何者正確？', '["該法所稱薪資，係包括以實物方式給付之獎金、津貼及其他任何名義之經常性給與", "該法所稱之求職者，係指受雇主僱用從事工作獲致薪資者", "該法所稱雇主，係指僱用受僱者之私立機構或機關，而不包括公立機構或機關", "該法所稱要派單位，係指從事勞動派遣業務之事業單位"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:04+00:00", "source_pdf_sha1": "f79244208669", "answer_pdf_sha1": "b0e444a8d54a", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "401", "s": "0607", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識(包括中華民國憲法、法學緒論)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "civil_slug": "aviation", "civil_category": "飛航諮詢"}'::jsonb, NULL),
  ('aviation-6c581c7e-moex-00091', 'aviation-6c581c7e', 'aviation-6c581c7e-moex-112-7bf35b0f', 'sub-aviation-6c581c7e-04', NULL, 'single_choice', '下列情形何者符合性別工作平等法第10條有關同工（值）同酬之規定？', '["甲男與乙女在A公司從事相同之搬運工作，A公司認為男性負重能力較佳，同樣從事搬運工作，男 性員工之貢獻當然比女性員工為多，因此，甲男每月工資較乙女多3,000元", "丙男與丁女在B公司從事清潔工作，B公司因認為男性體力較佳，故丙男每月工資較丁女多3,000元。 丁女不服，認為B公司之薪資政策違反同工同酬規定，要求B公司改善，否則即會到地方主管機關申 訴。B公司為避免受罰，因此調降丙男之工資，使丙男與丁女領取相同之工資", "戊男與己女在C公司從事相同工作，但「戊男」有主管頭銜，即便兩人工作價值相同，C公司仍得給 予戊男較高之薪資", "庚男與辛女在D公司從事相同工作，但庚男有碩士學位，辛女僅大學畢業，D公司得給予庚男較高 的起薪"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:04+00:00", "source_pdf_sha1": "f79244208669", "answer_pdf_sha1": "b0e444a8d54a", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "401", "s": "0607", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識(包括中華民國憲法、法學緒論)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "civil_slug": "aviation", "civil_category": "飛航諮詢"}'::jsonb, NULL),
  ('aviation-6c581c7e-moex-00092', 'aviation-6c581c7e', 'aviation-6c581c7e-moex-112-7bf35b0f', 'sub-aviation-6c581c7e-04', NULL, 'single_choice', '依司法院大法官解釋意旨，有關平等原則，下列敘述何者錯誤？', '["色盲者不得取得警察大學碩士班之入學資格，未違反平等原則", "非視障者不能從事按摩業，與所欲保障視障者工作權而生之就業利益相較，顯不相當，違反平等原則", "政府採購得標廠商於國內員工總人數逾100人者，應於履約期間僱用一定比例之原住民，違反平等原則", "祭祀公業條例施行前已存在之祭祀公業，以規約排除女子為派下員，未違反憲法保障性別平等之意旨"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:04+00:00", "source_pdf_sha1": "f79244208669", "answer_pdf_sha1": "b0e444a8d54a", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "401", "s": "0607", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識(包括中華民國憲法、法學緒論)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "civil_slug": "aviation", "civil_category": "飛航諮詢"}'::jsonb, NULL),
  ('aviation-6c581c7e-moex-00093', 'aviation-6c581c7e', 'aviation-6c581c7e-moex-112-7bf35b0f', 'sub-aviation-6c581c7e-04', NULL, 'single_choice', '行政執行法第3條規定，行政執行應以適當之方法為之，不得逾達成執行目的之必要限度，此為下列 何種原則之展現？', '["誠實信用原則", "不當聯結禁止原則", "預見可能性原則", "比例原則"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:04+00:00", "source_pdf_sha1": "f79244208669", "answer_pdf_sha1": "b0e444a8d54a", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "401", "s": "0607", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識(包括中華民國憲法、法學緒論)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "civil_slug": "aviation", "civil_category": "飛航諮詢"}'::jsonb, NULL)
